class Solution(object):
    def modifiedList(self, nums, head):
        nums_set = set(nums)
        dummy = ListNode(0)
        dummy.next = head
        prev = dummy
        while prev.next:
            if prev.next.val in nums_set:
                prev.next = prev.next.next
            else:
                prev = prev.next
        return dummy.next
